import { merge } from 'lodash-es';

import type { ConnectionTooltipStatePayload } from '../../../types/connection-layer.js';

export const restoreNullProps = (
  data: ConnectionTooltipStatePayload[] | undefined,
): Omit<ConnectionTooltipStatePayload, '__nullValues'>[] | undefined =>
  data?.map(({ __nullValues, ...rest }) => {
    const nullProps = __nullValues?.map((prop) => ({ [prop]: null })) || [];
    return merge(rest, ...nullProps);
  });
